export const consultationsUpdateSummary = async (id: string,
    summaryUpdateDto: SummaryUpdateDto, options?: RequestInit): Promise<ConsultationDtoOutput> => {

  return customFetch<ConsultationDtoOutput>(getConsultationsUpdateSummaryUrl(id),
  {
    ...options,
    method: 'PATCH',
    headers: { 'Content-Type': 'application/json', ...options?.headers },
    body: JSON.stringify(summaryUpdateDto)
  }
);}





